const MAX_ROWS = 200

if (msg.topic === "clear-log") {
    context.set('log', [])
    msg.topic = ''
    msg.payload = []
    return msg
}

const incomingMessage = msg.payload
let log = context.get('log') || []
if (!Array.isArray(log)) {
    log = []
}

let logMessages = normaliseLogEntry(msg.payload)

function normaliseLogEntry(data) {
    const result = []
    if (data === null) {
        return normaliseLogEntry("null")
    } else if (typeof data === "undefined") {
        return normaliseLogEntry("undefined")
    } else if (typeof data === 'number') {
        return normaliseLogEntry("" + data)
    } else if (Array.isArray(data)) {
        const arrStr = ["["]
        for (let index = 0; index < data.length; index++) {
            if (index > 0) { arrStr.push(', ') }
            arrStr.push(normaliseLogEntry(data[index]))
        }
        arrStr.push("]")
        return normaliseLogEntry(arrStr.join(''))
    } else if (typeof data === 'object') {
        result.push("> " + JSON.stringify(data, null, 2))
    } else if (Buffer.isBuffer(data)) {
        result.push("> " + data.toJSON())
    } else if (data && typeof data !== 'string') {
        result.push("> " + data.toString())
    } else {
        if (data.includes('\n')) {
            const lines = data.split('\n').map(m => "> " + m)
            result.push(...lines)
        } else {
            result.push("> " + data)
        }
    }
    return result
}

log.push(...logMessages.flat())

if (log.length >= MAX_ROWS) {
    // remove the oldest messages which are at the beginning of the array
    log = log.slice(-MAX_ROWS)
}

context.set('log', log)
msg.payload = log
return msg
